import React, { useState } from "react";
import { TextField, Button, Box, Typography, CircularProgress, Paper } from "@mui/material";
import { useNavigate } from "react-router-dom";
import api from "../services/api"; // axios instance

export default function Register() {
  const [mobile, setMobile] = useState("");
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState("");
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMsg("");
    try {
      setLoading(true);
      const res = await api.post("/auth/signup", { mobile }); // ✅ Correct backend route
      setMsg(res.data.message || "Registered successfully");
      setTimeout(() => navigate("/login"), 1000);
    } catch (err) {
      setMsg(err?.response?.data?.message || "Registration failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        height: "100vh",
        bgcolor: "#f5f5f5",
      }}
    >
      <Paper elevation={3} sx={{ p: 4, maxWidth: 400, width: "100%" }}>
        <Typography variant="h5" gutterBottom align="center">
          Register
        </Typography>
        <form onSubmit={handleSubmit}>
          <TextField
            label="Mobile Number"
            fullWidth
            margin="normal"
            value={mobile}
            onChange={(e) => setMobile(e.target.value)}
            required
          />
          <Button
            type="submit"
            variant="contained"
            color="primary"
            fullWidth
            disabled={loading}
            sx={{ mt: 2 }}
          >
            {loading ? <CircularProgress size={24} color="inherit" /> : "Register"}
          </Button>
        </form>
        {msg && (
          <Typography variant="body2" sx={{ mt: 2, color: msg.includes("success") ? "green" : "red" }}>
            {msg}
          </Typography>
        )}
      </Paper>
    </Box>
  );
}
